insert into public.zbiorniki (n, lat, lon, ha, t, r, a) values
  ('Zwięczyca', 50.00492, 21.95819, '1,90', 'Zbiornik pożwirowy', 'Zakaz używania łódek zdalnie sterowanych do wywożenia zanęt i przynęt.', 1),
  ('Błażkowa, Brzyska', 49.85176, 21.37876, '29,94', '5 wyrobisk pożwirowych', 'Zakaz zabierania i przetrzymywania karpi na stawie nr 4.', 1),
